import{g as a,b as i,c as n,h as e}from"./chunks/framework.B3PWxpU3.js";const d=JSON.parse('{"title":"UWP开发:在一个应用中使用两套WinUI主题","description":"","frontmatter":{"date":"2023-06-23T00:00:00.000Z","title":"UWP开发:在一个应用中使用两套WinUI主题","excerpt":"2021年6月，微软发布了WinUI 2.6更新，其中包含了符合Win11设计的全新控件样式。但为避免部分应用不兼容新样式，旧版的控件样式仍然被保留了下来。本文将介绍使用旧版样式的两种方法。","tag":["C#","UWP","WinUI","XAML"]},"headers":[],"relativePath":"posts/在一个应用中使用两套WinUI主题/index.md","filePath":"posts/在一个应用中使用两套WinUI主题/index.md"}'),l={name:"posts/在一个应用中使用两套WinUI主题/index.md"};function p(t,s,h,r,o,k){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h2 id="在xaml中更改" tabindex="-1">在XAML中更改 <a class="header-anchor" href="#在xaml中更改" aria-label="Permalink to “在XAML中更改”">​</a></h2><blockquote><p>在 <a href="https://learn.microsoft.com/zh-cn/windows/apps/design/style/xaml-styles#winui-and-styles" target="_blank" rel="noreferrer">https://learn.microsoft.com/zh-cn/windows/apps/design/style/xaml-styles#winui-and-styles</a> 中介绍了在XAML中切换旧版本的方式。</p></blockquote><p>在<code>App.xaml</code>中的<code>XamlControlsResources</code>内添加一个属性：</p><p><code>ControlsResourcesVersion=&quot;Version1&quot;</code></p><p>启动应用，就可以看到旧版的控件样式了。</p><h2 id="在代码中更改" tabindex="-1">在代码中更改 <a class="header-anchor" href="#在代码中更改" aria-label="Permalink to “在代码中更改”">​</a></h2><p>在应用运行的时候，如果我们用XAML热重载强行更改<code>App.xaml</code>中的样式版本，应用就会因资源冲突闪退</p><p>如果在App.xaml.cs中直接给App.Resources添加<code>XamlControlsResources</code>，你会喜提一个报错： <img src="/posts/%E5%9C%A8%E4%B8%80%E4%B8%AA%E5%BA%94%E7%94%A8%E4%B8%AD%E4%BD%BF%E7%94%A8%E4%B8%A4%E5%A5%97WinUI%E4%B8%BB%E9%A2%98/01.png" alt=""></p><p>因此，在应用运行或启动时直接更改资源版本是行不通的，我们需要在XAML资源加载之前更改样式的版本</p><h3 id="_1-创建主题文件" tabindex="-1">1.创建主题文件 <a class="header-anchor" href="#_1-创建主题文件" aria-label="Permalink to “1.创建主题文件”">​</a></h3><p>创建一个资源字典<code>Theme.xaml</code>(也可为其他命名)</p><p>同时创建后台代码<code>Theme.xaml.cs</code>，此时VS会自动合并两个文件</p><p>在Theme.xaml中添加x:Class属性以使用后台代码</p><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes vs-light vs-dark" style="--shiki-light:#000000;--shiki-dark:#DCDCDC;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">x:Class=&quot;WinUIThemeTest.Theme&quot;</span></span></code></pre></div><p>同时在<code>Theme.xaml.cs</code>中作出如下更改</p><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes vs-light vs-dark" style="--shiki-light:#000000;--shiki-dark:#DCDCDC;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">namespace</span><span style="--shiki-light:#2B91AF;--shiki-dark:#4EC9B0;"> WinUIThemeTest</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">{</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">    internal</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> partial</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> class</span><span style="--shiki-light:#2B91AF;--shiki-dark:#4EC9B0;"> Theme</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">:</span><span style="--shiki-light:#2B91AF;--shiki-dark:#4EC9B0;">ResourceDictionary</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">    {</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">        public</span><span style="--shiki-light:#74531F;--shiki-dark:#DCDCAA;"> Theme</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">()</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">        {</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">            this.</span><span style="--shiki-light:#74531F;--shiki-dark:#DCDCAA;">InitializeComponent</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">();</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">        }</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">    }</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">}</span></span></code></pre></div><h3 id="_2-编写后台代码" tabindex="-1">2.编写后台代码 <a class="header-anchor" href="#_2-编写后台代码" aria-label="Permalink to “2.编写后台代码”">​</a></h3><p>这时候，我们就可以在Theme的构造函数中对这个资源字典进行合并操作了:</p><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes vs-light vs-dark" style="--shiki-light:#000000;--shiki-dark:#DCDCDC;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">public</span><span style="--shiki-light:#74531F;--shiki-dark:#DCDCAA;"> Theme</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">()</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">{</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">      this.</span><span style="--shiki-light:#74531F;--shiki-dark:#DCDCAA;">InitializeComponent</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">();</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">      this.MergedDictionaries.</span><span style="--shiki-light:#74531F;--shiki-dark:#DCDCAA;">Add</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">(</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">new</span><span style="--shiki-light:#2B91AF;--shiki-dark:#4EC9B0;"> XamlControlsResources</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;"> { </span><span style="--shiki-light:#000000;--shiki-dark:#9CDCFE;">ControlsResourcesVersion</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> =</span><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;"> ControlsResourcesVersion.Version1 });</span></span>
<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#DCDCDC;">}</span></span></code></pre></div><h3 id="_3-添加到app-xaml" tabindex="-1">3.添加到App.xaml <a class="header-anchor" href="#_3-添加到app-xaml" aria-label="Permalink to “3.添加到App.xaml”">​</a></h3><p>在App.xaml中添加此资源字典:</p><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes vs-light vs-dark" style="--shiki-light:#000000;--shiki-dark:#DCDCDC;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&lt;Application.Resources&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">    &lt;ResourceDictionary&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">        &lt;ResourceDictionary.MergedDictionaries&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">            &lt;local:Theme/&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">        &lt;/ResourceDictionary.MergedDictionaries&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">    &lt;/ResourceDictionary&gt;</span></span>
<span class="line"><span style="--shiki-light:#800000;--shiki-dark:#569CD6;">&lt;/Application.Resources&gt;</span></span></code></pre></div><p>这时，我们启动后同样可以看到旧版控件样式。</p><h3 id="_4-更改逻辑" tabindex="-1">4.更改逻辑 <a class="header-anchor" href="#_4-更改逻辑" aria-label="Permalink to “4.更改逻辑”">​</a></h3><p>后台代码控制<code>XamlControlsResources</code>版本的好处就是可以根据需求任意更改版本，比如:</p><p>(Theme.xaml.cs)</p><div class="language-CSH"><button title="Copy Code" class="copy"></button><span class="lang">CSH</span><pre class="shiki shiki-themes vs-light vs-dark" style="--shiki-light:#000000;--shiki-dark:#DCDCDC;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>public Theme()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>    this.InitializeComponent();</span></span>
<span class="line"><span>    if (Environment.OSVersion.Version.Build &gt;= 22000)//判断系统是否为Win11</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>        this.MergedDictionaries.Add(new XamlControlsResources { ControlsResourcesVersion = ControlsResourcesVersion.Version2 });//添加新版本控件样式</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    else</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>        this.MergedDictionaries.Add(new XamlControlsResources { ControlsResourcesVersion = ControlsResourcesVersion.Version1 });//添加旧版本控件样式</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>这样，就可以根据系统版本使用不同控件样式了。 （当然，也可以自己写一些其他的逻辑，如在设置中切换样式等等）</p><h2 id="最终效果" tabindex="-1">最终效果 <a class="header-anchor" href="#最终效果" aria-label="Permalink to “最终效果”">​</a></h2><h3 id="旧版样式" tabindex="-1">旧版样式 <a class="header-anchor" href="#旧版样式" aria-label="Permalink to “旧版样式”">​</a></h3><p><img src="/posts/%E5%9C%A8%E4%B8%80%E4%B8%AA%E5%BA%94%E7%94%A8%E4%B8%AD%E4%BD%BF%E7%94%A8%E4%B8%A4%E5%A5%97WinUI%E4%B8%BB%E9%A2%98/02.png" alt=""></p><h3 id="新版样式" tabindex="-1">新版样式 <a class="header-anchor" href="#新版样式" aria-label="Permalink to “新版样式”">​</a></h3><p><img src="/posts/%E5%9C%A8%E4%B8%80%E4%B8%AA%E5%BA%94%E7%94%A8%E4%B8%AD%E4%BD%BF%E7%94%A8%E4%B8%A4%E5%A5%97WinUI%E4%B8%BB%E9%A2%98/03.png" alt=""></p><h2 id="源码" tabindex="-1">源码 <a class="header-anchor" href="#源码" aria-label="Permalink to “源码”">​</a></h2><p><a href="https://github.com/zxbmmmmmmmmm/WinUIThemeSample" target="_blank" rel="noreferrer">https://github.com/zxbmmmmmmmmm/WinUIThemeSample</a></p><h2 id="思路参考" tabindex="-1">思路参考 <a class="header-anchor" href="#思路参考" aria-label="Permalink to “思路参考”">​</a></h2><p><a href="https://github.com/character-map-uwp/Character-Map-UWP" target="_blank" rel="noreferrer">https://github.com/character-map-uwp/Character-Map-UWP</a></p>`,37)])])}const C=a(l,[["render",p]]);export{d as __pageData,C as default};
